namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private OrderService _service = null!;

    [TestInitialize]
    public void Setup()
    {
        _service = new OrderService();
    }

    // --- CreateOrder: happy-path ---

    [TestMethod]
    public void CreateOrder_WithValidItems_ReturnsOrderWithCorrectCustomerId()
    {
        var items = MakeItems(("Widget", 9.99m, 1));

        var order = _service.CreateOrder("cust-1", items);

        Assert.AreEqual("cust-1", order.CustomerId);
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_AssignsNonEmptyId()
    {
        var items = MakeItems(("Widget", 9.99m, 1));

        var order = _service.CreateOrder("cust-1", items);

        Assert.IsFalse(string.IsNullOrWhiteSpace(order.Id));
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_SetsCreatedAtToRecentUtcTime()
    {
        var before = DateTime.UtcNow;
        var items = MakeItems(("Widget", 9.99m, 1));

        var order = _service.CreateOrder("cust-1", items);

        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= DateTime.UtcNow);
    }

    [TestMethod]
    public void CreateOrder_SingleItem_CalculatesTotalCorrectly()
    {
        var items = MakeItems(("Widget", 5.00m, 3));

        var order = _service.CreateOrder("cust-1", items);

        Assert.AreEqual(15.00m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_MultipleItems_SumsTotalCorrectly()
    {
        var items = MakeItems(("A", 10.00m, 2), ("B", 3.50m, 4));

        var order = _service.CreateOrder("cust-1", items);

        Assert.AreEqual(34.00m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_StoresAllSuppliedItems()
    {
        var items = MakeItems(("X", 1m, 1), ("Y", 2m, 2));

        var order = _service.CreateOrder("cust-1", items);

        Assert.AreEqual(2, order.Items.Count);
    }

    [TestMethod]
    public void CreateOrder_CalledTwice_AssignsUniqueIds()
    {
        var items = MakeItems(("W", 1m, 1));

        var first = _service.CreateOrder("c1", items);
        var second = _service.CreateOrder("c2", items);

        Assert.AreNotEqual(first.Id, second.Id);
    }

    // --- CreateOrder: validation ---

    [TestMethod]
    public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
    {
        var items = MakeItems(("W", 1m, 1));

        Assert.ThrowsException<ArgumentNullException>(
            () => _service.CreateOrder(null!, items));
    }

    [TestMethod]
    public void CreateOrder_NullItems_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(
            () => _service.CreateOrder("cust-1", null!));
    }

    [TestMethod]
    public void CreateOrder_EmptyItems_ThrowsInvalidOperationException()
    {
        Assert.ThrowsException<InvalidOperationException>(
            () => _service.CreateOrder("cust-1", []));
    }

    // --- GetOrder ---

    [TestMethod]
    public void GetOrder_ExistingId_ReturnsMatchingOrder()
    {
        var created = _service.CreateOrder("cust-1", MakeItems(("W", 1m, 1)));

        var retrieved = _service.GetOrder(created.Id);

        Assert.IsNotNull(retrieved);
        Assert.AreEqual(created.Id, retrieved.Id);
    }

    [TestMethod]
    public void GetOrder_UnknownId_ReturnsNull()
    {
        var result = _service.GetOrder("does-not-exist");

        Assert.IsNull(result);
    }

    [TestMethod]
    public void GetOrder_AfterMultipleCreates_ReturnsCorrectOrder()
    {
        _service.CreateOrder("c1", MakeItems(("A", 1m, 1)));
        var target = _service.CreateOrder("c2", MakeItems(("B", 2m, 2)));
        _service.CreateOrder("c3", MakeItems(("C", 3m, 3)));

        var retrieved = _service.GetOrder(target.Id);

        Assert.IsNotNull(retrieved);
        Assert.AreEqual("c2", retrieved.CustomerId);
    }

    // --- GetOrdersByCustomer ---

    [TestMethod]
    public void GetOrdersByCustomer_NoOrders_ReturnsEmptyList()
    {
        var result = _service.GetOrdersByCustomer("unknown");

        Assert.AreEqual(0, result.Count);
    }

    [TestMethod]
    public void GetOrdersByCustomer_OneMatch_ReturnsSingleOrder()
    {
        _service.CreateOrder("cust-1", MakeItems(("W", 1m, 1)));
        _service.CreateOrder("cust-2", MakeItems(("W", 1m, 1)));

        var result = _service.GetOrdersByCustomer("cust-1");

        Assert.AreEqual(1, result.Count);
        Assert.AreEqual("cust-1", result[0].CustomerId);
    }

    [TestMethod]
    public void GetOrdersByCustomer_MultipleMatches_ReturnsAllMatchingOrders()
    {
        _service.CreateOrder("cust-1", MakeItems(("A", 1m, 1)));
        _service.CreateOrder("cust-1", MakeItems(("B", 2m, 1)));
        _service.CreateOrder("cust-2", MakeItems(("C", 3m, 1)));

        var result = _service.GetOrdersByCustomer("cust-1");

        Assert.AreEqual(2, result.Count);
        Assert.IsTrue(result.All(o => o.CustomerId == "cust-1"));
    }

    // --- helper ---

    private static List<OrderItem> MakeItems(params (string Name, decimal Price, int Qty)[] defs) =>
        defs.Select(d => new OrderItem
        {
            ProductName = d.Name,
            Price = d.Price,
            Quantity = d.Qty
        }).ToList();
}

